const { Client } = require('@elastic/elasticsearch');

// Initialize Elasticsearch client
const client = new Client({ node: 'http://localhost:9200' });

async function performAdvancedSearch(queryParams) {
  const { index, query, script } = queryParams;

  // Construct the search body with script_score query
  const searchBody = {
    query: {
      script_score: {
        query,
        script: {
          source: script
        }
      }
    }
  };

  try {
    const response = await client.search({
      index,
      body: searchBody
    });

    return response.body.hits.hits;
  } catch (error) {
    console.error('Error performing search:', error);
    throw error;
  }
}

